/* Call this if and only if unit test is to be invoked before subsystem 
 * initialization but after memory management system is initialized.
 * sesut_ermi_r_fsmtest_memoryinit ensures that internal data structures
 * are ready.
 */
void sesut_ermi_r_fsmtest_memoryinit (void) {

    /* If chunk memory is already created then there is nothing to do. */
    if (sesut_ermi_r_fsmtest_chunk!=NULL) {
        return;
    }
    /* If in low memory mode do not create chunk memory. */
    if (sesut_ermi_r_fsmtest_max_testinfo_blocks_defined && 
          (sesut_ermi_r_fsmtest_max_testinfo_blocks==0)) {
        return;
    }
    if (sesut_ermi_r_fsmtest_chunk==NULL) {
        sesut_ermi_r_fsmtest_chunk=chunk_create(sizeof(sesut_ermi_r_fsmtest_testinfo),
                sesut_ermi_r_fsmtest_max_testinfo_blocks,CHUNK_FLAGS_DYNAMIC,
                NULL,0,"sesut_ermi_r_fsmtest local testinfo");
        if (sesut_ermi_r_fsmtest_chunk==NULL) {
            buginf("\nSESUT: sesut_ermi_r_fsmtest Chunk create failed");
            sesut_ermi_r_fsmtest_current=NULL;
            return;
        }
    }
}

/*
 * Function frees memory used to store test results
 */
static void sesut_ermi_r_fsmtest_free_memory (void) {

    sesut_ermi_r_fsmtest_testinfo *current,*next;
    uint res;

    current=sesut_ermi_r_fsmtest_listhead;
    while (current!=NULL) {
        next=(current->next);
        
        if (current->param1){
free(current->param1);
}
        chunk_free(sesut_ermi_r_fsmtest_chunk,current);
        current=next;
    }
    sesut_ermi_r_fsmtest_listhead=NULL;
    sesut_ermi_r_fsmtest_current=NULL;
    sesut_ermi_r_fsmtest_times_cli_used=0;
    sesut_ermi_r_fsmtest_times_api_used=0;
    sesut_ermi_r_fsmtest_times_defaultapi_used=0;
    sesut_ermi_r_fsmtest_number_of_testinfo_blocks=0;

    if (sesut_ermi_r_fsmtest_chunk != NULL) {
        res = chunk_destroy( sesut_ermi_r_fsmtest_chunk);
        if (!res) {
            printf("\nSESUT:error> Chunk:sesut_ermi_r_fsmtest_chunk: is not empty");
        }
    }
    sesut_ermi_r_fsmtest_chunk = NULL;
}

