/* Print status */
void sesut_ermi_r_fsmtest_status_parse (parseinfo* csb) {

   /* Check if we need to provide detailed information */
   if (GETOBJ(int,1)==0) {
       /* Check if we need to direct output to URL */
       if (strncmp(GETOBJ(string,1),"",1)==0) {
           sesut_ermi_r_fsmtest_status();
       } else {
           sesut_stdout_to_url(sesut_ermi_r_fsmtest_status,GETOBJ(string,1),
              SESUT_STDOUT_REDIRECT);
       }
   } else {
       /* Check if we need to direct output to URL */
       if (strncmp(GETOBJ(string,1),"",1)==0) {
           sesut_ermi_r_fsmtest_status_detailed();
       } else {
           sesut_stdout_to_url(sesut_ermi_r_fsmtest_status_detailed,GETOBJ(string,1),
              SESUT_STDOUT_REDIRECT);
       }
   }
}


/* Print status  - called from "globalsesut status" */
void sesut_ermi_r_fsmtest_get_status (boolean detailed, char *url) {
   /* Check if we need to provide detailed information */
   if (detailed) {
       /* Check if we need to direct output to URL */
       if (strncmp(url,"",1)==0) {
           sesut_ermi_r_fsmtest_status_detailed();
       } else {
           sesut_stdout_to_url(sesut_ermi_r_fsmtest_status_detailed,url,
              SESUT_STDOUT_APPEND);
       }
   } else {
       /* Check if we need to direct output to URL */
       if (strncmp(url,"",1)==0) {
           sesut_ermi_r_fsmtest_status();
       } else {
           sesut_stdout_to_url(sesut_ermi_r_fsmtest_status,url,
              SESUT_STDOUT_APPEND);
       }
   }
}


/*
 * This function prints information about
 * the unit test and the history of test executions.
 */
void sesut_ermi_r_fsmtest_status () {

    sesut_ermi_r_fsmtest_testinfo *current;
    uint block_count, test_count;

    if ((sesut_ermi_r_fsmtest_times_cli_used+sesut_ermi_r_fsmtest_times_api_used+
           sesut_ermi_r_fsmtest_times_defaultapi_used)>0) {
        if (sesut_ermi_r_fsmtest_listhead==NULL) {
            printf("\nsesut_ermi_r_fsmtest has been executed but there is no "
                   "log of activity.");
        } else {
            printf("\nsesut_ermi_r_fsmtest has been executed.");
        }
    } else {
        printf("\nsesut_ermi_r_fsmtest has not been executed.");
    }
    printf("\nUnit test description file is - %s","/vob/ios.sys7/sys/obj-sp-unixrp/ermi_r_fsmtest.sesut");
    if (testinfo.isDynamicLoaded) {
	printf("\nThis SESUT test is dynamically loaded");
	printf("\nThe current version is %u",testinfo.sesutVersion);
    }
    printf("\nModel used is - Digraph");
    if (sesut_ermi_r_fsmtest_dtd_availability) {
        printf("\nAPI robustness tests are available.");
    } else {
        printf("\nThere is no API robustness test.");
    }
    printf("\nDefault repeat count is -  %u",
        sesut_ermi_r_fsmtest_default_repeatcount);
    printf("\nThis test does not alter the global state.\nThis test can be executed under IOU.");
    printf("\nInitializer function is not specified.");
    printf("\nFinalizer function is not specified.");
    printf("\nPre-test function is not specified.");
    printf("\nPost-test function is not specified.");
    printf("\nPre-test function(with parameters) is not specified.");
    printf("\nPost-test function(with parameters) is not specified.");
    if (sesut_ermi_r_fsmtest_trace_status==SESUT_ERMI_R_FSMTEST_TRACE_ON) {
        printf("\nTrace is on.");
    } else {
        printf("\nTrace is off.");
    }

    if (sesutFlushLoggerAfterTest) {
   	printf("\nFlush logger is on.");
    } else {
	printf("\nFlush logger is off.");
    }
    
    printf("\nThe test has 1 parameter(s)."
        "\nInformation about parameter(s)(Parameter Variable Type Default):"
        "\n1 peer_addr addrtype* NULL"
        );

    printf("\nNumber of times invoked via CLI - %lu",
                                  sesut_ermi_r_fsmtest_times_cli_used);
    printf("\nNumber of times invoked via API - %lu",
                                  sesut_ermi_r_fsmtest_times_api_used);
    printf("\nNumber of times invoked via API(defaults) - %lu",
                                  sesut_ermi_r_fsmtest_times_defaultapi_used);
    printf("\nMaximum number of entries in the log - %u",
                                  sesut_ermi_r_fsmtest_max_testinfo_blocks);
    block_count=0;
    current=sesut_ermi_r_fsmtest_listhead;
    while (current!=NULL) {
        block_count++;
        current=current->next;
    }
    printf("\nNumber of entries in the log - %u",block_count);
    /* If we have no log then return. */
    if (sesut_ermi_r_fsmtest_listhead==NULL) {
        return;
    }

    sesut_ermi_r_fsmtest_print_timer_info();
    printf("\nUse caution in interpreting the time information.");
    printf("\nThese are elapsed times. Any activity on the system");
    printf("\nis included in the times reported. Repeat your tests.");

    /* Print summary statistics.*/
    printf("\n\nSummary statistics:");
    current=sesut_ermi_r_fsmtest_listhead;
    printf("\nRepeatcount:");
    while (current!=NULL) {
        printf(" %u",current->repeatcount);
        current=current->next;
    }
    current=sesut_ermi_r_fsmtest_listhead;
    printf("\nScalefactor:");
    while (current!=NULL) {
        printf(" %u",current->scalefactor);
        current=current->next;
    }
    current=sesut_ermi_r_fsmtest_listhead;
    printf("\nExecutiontime:");
    while (current!=NULL) {
        printf(" %lld",current->executiontime);
        current=current->next;
    }
    current=sesut_ermi_r_fsmtest_listhead;
    printf("\nMemory used(bytes):");
    while (current!=NULL) {
        printf(" %ld",current->memoryused);
        current=current->next;
    }
    current=sesut_ermi_r_fsmtest_listhead;
    printf("\nHow invoked:");
    while (current!=NULL) {
        if (current->howinvoked==SESUT_ERMI_R_FSMTEST_CLI_IN_USE) {
            printf(" CLI");
        } else if (current->howinvoked==SESUT_ERMI_R_FSMTEST_API_IN_USE) {
            printf(" API");
        } else if (current->howinvoked==SESUT_ERMI_R_FSMTEST_DEFAPI_IN_USE) {
            printf(" API(defaults)");
        } else {
            printf("\nInternal error - Unrecognized value for "
                   "how invoked.");
        }
        current=current->next;
    }
    current=sesut_ermi_r_fsmtest_listhead;
    test_count = 0;
    printf("\nTest result:");
    while (current!=NULL) {
    uint i;	
	test_count++;
        switch (current->testresult) {
        case SESUT_ERMI_R_FSMTEST_TEST_RESULT_UNKNOWN:
            printf("\n %u. Unknown", test_count);
            break;
        case SESUT_ERMI_R_FSMTEST_TEST_PASSED:
            printf("\n %u. Pass (%d passes/%d failures)", test_count,
	           current->count_of_passes, current->count_of_failures);
            break;
        case SESUT_ERMI_R_FSMTEST_TEST_FAILED:
     	    printf("\n %u. Fail (%d passes/%d failures)", test_count, 
	           current->count_of_passes, current->count_of_failures);
	        for (i=0;i<=current->count_of_failures&&i<MAX_FAIL_COUNT;i++) {
                sesut_output_failmessage(current->cause_for_failure[i],
                       255,
                       "     ",SESUT_OUTPUT_LINE_LEN);	        	
	        }   
            break;
        default:
            printf("\nInternal error - Unrecognized value for test result.");
        }
        current=current->next;
    }

    /* Print values of parameters. */
    printf("\n\nValue(s) of parameter(s):");
    current=sesut_ermi_r_fsmtest_listhead;
    printf("\npeer_addr");
    while (current!=NULL) {
        printf(" %i",current->param1->ip_addr);
        current=current->next;
    }

}


/*
 * This function prints detailed information about
 * the unit test.
 */
void sesut_ermi_r_fsmtest_status_detailed () {

    sesut_ermi_r_fsmtest_testinfo *current;
    uint index, test_count;
    uint next_column=7;

    /* First print the usual information. */
    sesut_ermi_r_fsmtest_status();

    /* If no test has been executed then nothing to print*/
    if (sesut_ermi_r_fsmtest_listhead==NULL) {
        return;
    }
    printf("\n\nFollowing table provides performance/scalability"
           " data\nthat can be exported to a data analysis program.");
    printf("\n\nWe are looking for a lightweight data analysis"
           " package\nthat can be included in SESUT images.");
    printf("\nColumn Heading");
    printf("\n------ -------");
    printf("\n1 repeatcount");
    printf("\n2 scalefactor");
    printf("\n3 executiontime");
    printf("\n4 memoryused");
    printf("\n5 howinvoked");
    printf("\n6 testresult");
    printf("\n%u Parameter peer_addr",next_column);
    next_column++;
    for (index=0;index<1;index++) {
        printf("\n%u %s(count)",next_column,
                sesut_ermi_r_fsmtest_graphLabels[index]);
        next_column++;
        printf("\n%u %s(time)",next_column,
                sesut_ermi_r_fsmtest_graphLabels[index]);
        next_column++;
    }
    printf("\n");

    current=sesut_ermi_r_fsmtest_listhead;
    test_count =0;
    while (current!=NULL) {
        test_count++;
        printf("\n%u",current->repeatcount);
        printf(" %u",current->scalefactor);
        printf(" %lld",current->executiontime);
        printf(" %ld",current->memoryused);
        if (current->howinvoked==SESUT_ERMI_R_FSMTEST_CLI_IN_USE) {
            printf(" CLI");
        } else if (current->howinvoked==SESUT_ERMI_R_FSMTEST_API_IN_USE) {
            printf(" API");
        } else if (current->howinvoked==SESUT_ERMI_R_FSMTEST_DEFAPI_IN_USE) {
            printf(" API(defaults)");
        } else {
            printf("\nInternal error - Unrecognized value for "
                   "how invoked.");
        }
        switch (current->testresult) {
        case SESUT_ERMI_R_FSMTEST_TEST_RESULT_UNKNOWN:
            printf(" Unknown");
            break;
        case SESUT_ERMI_R_FSMTEST_TEST_PASSED:
            printf(" Pass (%d passes/%d failures)",
            current->count_of_passes,current->count_of_failures);
            break;
        case SESUT_ERMI_R_FSMTEST_TEST_FAILED:
	        printf(" Fail (%d passes/%d failures)",
            current->count_of_passes,current->count_of_failures);
            break;
        default:
            printf("\nInternal error - Unrecognized value for "
                   "test result.\n");
        }
        printf(" %i",current->param1->ip_addr);
        for (index=0;index<1;index++) {
            printf(" %u %lld",current->nodes_and_edges[index].count,
                   current->nodes_and_edges[index].time);
        }
        current=current->next;
    }
}

