/*
 * This function clears data structures
 * Could be invoked via CLI or API.
 * Free memory allocated to save string parameters.
 * Free test info. blocks.
 */
static void sesut_ermi_r_fsmtest_clear (void) {
    sesut_ermi_r_fsmtest_testinfo *current,*next;

    current=sesut_ermi_r_fsmtest_listhead;
    while (current!=NULL) {
        next=(current->next);
        
        if (current->param1){
free(current->param1);
}
        chunk_free(sesut_ermi_r_fsmtest_chunk,current);
        current=next;
    }
    sesut_ermi_r_fsmtest_listhead=NULL;
    sesut_ermi_r_fsmtest_current=NULL;
    sesut_ermi_r_fsmtest_times_cli_used=0;
    sesut_ermi_r_fsmtest_times_api_used=0;
    sesut_ermi_r_fsmtest_times_defaultapi_used=0;
    sesut_ermi_r_fsmtest_number_of_testinfo_blocks=0;
    sesut_ermi_r_fsmtest_dtd_all=FALSE;
    sesut_ermi_r_fsmtest_dtd_singlefn=FALSE;
    sesut_ermi_r_fsmtest_dtd_notest=FALSE;
}

