void sesut_ermi_r_fsmtest_testpass (void) {
    if (sesut_ermi_r_fsmtest_current!=NULL) {
    	sesut_ermi_r_fsmtest_current->count_of_passes++;
        if (sesut_ermi_r_fsmtest_current->testresult==SESUT_ERMI_R_FSMTEST_TEST_FAILED) {
        	return;
        } else {
            sesut_ermi_r_fsmtest_current->testresult=SESUT_ERMI_R_FSMTEST_TEST_PASSED;
            if (sesut_global_log_result) {
                buginf("\nSESUT Log: Test sesut_ermi_r_fsmtest passed");
            }
        }
    }
}

/* Call sesut_ermi_r_fsmtest_testfail to indicate test failure.
 * The length of the formatted string should be less than or equal 
 * to 255.Else it will be 
 * truncated.
 */
void sesut_ermi_r_fsmtest_testfail (const char *fmt, ...) {

    va_list ap;
    int count;
    int fail_count;

    /* Record only the first MAX_FAIL_COUNT fail messages. */
    if (sesut_ermi_r_fsmtest_current!=NULL) {
    	fail_count = sesut_ermi_r_fsmtest_current->count_of_failures++;
        sesut_ermi_r_fsmtest_current->testresult=SESUT_ERMI_R_FSMTEST_TEST_FAILED;
        if (fail_count < MAX_FAIL_COUNT) {
            va_start(ap, fmt);
            /* vsnprintf in IOS does not return -1 for error.. */
            count = vsnprintf(sesut_ermi_r_fsmtest_current->
                 cause_for_failure[fail_count],
                 255, fmt, ap);
            sesut_ermi_r_fsmtest_current->cause_for_failure[fail_count][count] = '\0';
            va_end(ap);
        } else {
            buginf("\nSESUT log: Buffer full: Only first %d failure messages are logged.",
            MAX_FAIL_COUNT);	
        }
        if (sesut_global_log_result) {
            buginf("\nSESUT Log: Test sesut_ermi_r_fsmtest failed - %s",
            sesut_ermi_r_fsmtest_current->
              cause_for_failure[sesut_ermi_r_fsmtest_current->count_of_failures]);
        }
    }
}


/*
 * Allocate a testifo block.
 * Set current block to the new block. This could be NULL.
 * If allocation fails after list is establishes(has atleast one
 * element) then the list is made into a circular list.
 * If we hit the limit on the number of blocks after list is 
 * establishes(has atleast one element) then the list is made into 
 * a circular list.
 */
void sesut_ermi_r_fsmtest_gettestinfoblock (void) {
    void *newblock;

    if (sesut_ermi_r_fsmtest_max_testinfo_blocks_defined && 
          (sesut_ermi_r_fsmtest_max_testinfo_blocks==0)) {
        sesut_ermi_r_fsmtest_current=NULL;
        return;
    }
    /* Check if we reached the limit on number of blocks */
    if (sesut_ermi_r_fsmtest_max_testinfo_blocks_defined && 
                (sesut_ermi_r_fsmtest_number_of_testinfo_blocks==
                  sesut_ermi_r_fsmtest_max_testinfo_blocks)) {
        /* We can't add any more blocks. Reached the limit. 
         * Let us make our list into a circular list.
         * This should work even if we already have a circular list.
         * Should work even if the max is 1.
         */
        sesut_ermi_r_fsmtest_current->next=sesut_ermi_r_fsmtest_listhead;
        sesut_ermi_r_fsmtest_current=sesut_ermi_r_fsmtest_listhead;
        sesut_ermi_r_fsmtest_listhead=sesut_ermi_r_fsmtest_listhead->next;
        bzero(sesut_ermi_r_fsmtest_current,sizeof(sesut_ermi_r_fsmtest_testinfo));
        return;
    }
    /* Create chunk if needed */
    sesut_ermi_r_fsmtest_memoryinit();
    if (sesut_ermi_r_fsmtest_chunk==NULL) {
        sesut_ermi_r_fsmtest_current=NULL;
        return;
    }
    /* Let us try to get a block of memory */
    newblock=chunk_malloc(sesut_ermi_r_fsmtest_chunk);
    if (newblock!=NULL) {
        if (sesut_ermi_r_fsmtest_listhead==NULL) {
            sesut_ermi_r_fsmtest_listhead=newblock; 
        } else {
            sesut_ermi_r_fsmtest_current->next=newblock;
        }
        sesut_ermi_r_fsmtest_current=newblock;
        sesut_ermi_r_fsmtest_number_of_testinfo_blocks++;
        return;
    } else {
        buginf("\nSESUT: sesut_ermi_r_fsmtest Chunk malloc failed");
        if (sesut_ermi_r_fsmtest_number_of_testinfo_blocks==0) {
            sesut_ermi_r_fsmtest_current=NULL;
            return;
        }
        /* We cant add any more blocks. Let us make our list
         * into a circular list.
         */
        sesut_ermi_r_fsmtest_current->next=sesut_ermi_r_fsmtest_listhead;
        sesut_ermi_r_fsmtest_current=sesut_ermi_r_fsmtest_listhead;
        sesut_ermi_r_fsmtest_listhead=sesut_ermi_r_fsmtest_listhead->next;
        bzero(sesut_ermi_r_fsmtest_current,sizeof(sesut_ermi_r_fsmtest_testinfo));
        return;
    }
}

/* Return the number of failures. Optionally print the failure
 * messages.
 */
static uint sesut_ermi_r_fsmtest_getfailurecount (boolean print_failuremessage) {
    uint failure_count;
    uint i;
    sesut_ermi_r_fsmtest_testinfo *current;

    failure_count=0;
    current=sesut_ermi_r_fsmtest_listhead;
    while (current!=NULL) {
        if (current->testresult==SESUT_ERMI_R_FSMTEST_TEST_FAILED) {
            failure_count++;
            if (print_failuremessage) {
                printf(" Test sesut_ermi_r_fsmtest failed  -\n");
                for (i=0;i<=current->count_of_failures&&i<MAX_FAIL_COUNT;i++) {
                    sesut_output_failmessage(current->cause_for_failure[i],
                       255,
                       "     ",SESUT_OUTPUT_LINE_LEN);                	
                }
            }
        }
        current=(current->next);
    }
    return failure_count;
}

/*
 * This function drives the unit test.
 * Receives the inputs via CLI.
 */
void sesut_ermi_r_fsmtest_harness (parseinfo *csb) {

    sesut_ermi_r_fsmtest_time starttime;
    ulong start_freememory;
    sesut_ermi_r_fsmtest_time sesut_current_executiontime;
    uint sesut_current_memoryused;
    
    boolean perform_gd,perform_mif,get_cflow,sesut_gdmifcflow_result;

    printf("\nExecuting unit test %s","sesut_ermi_r_fsmtest");
    /* If user has not entered values for parameters then use defaults. */
    if (GETOBJ(int,5)==SESUT_ERMI_R_FSMTEST_USE_PARAM_DEFAULTS) {
        printf("\nUsing default values for parameters.");
        SETOBJ(paddr,1) = dummyaddr;
    }


    /* Determine the repeat count */
    if (GETOBJ(int,1)==SESUT_ERMI_R_FSMTEST_REPEAT_SPECIFIED) {
        sesut_ermi_r_fsmtest_current_repeatcount=GETOBJ(int,2);
        printf("\nTest will be repeated %u time(s).",
              sesut_ermi_r_fsmtest_current_repeatcount);
    } else {
        sesut_ermi_r_fsmtest_current_repeatcount=sesut_ermi_r_fsmtest_default_repeatcount;
        printf("\nRepeat count is not specified. Test will be "
               "executed %u time(s).",sesut_ermi_r_fsmtest_default_repeatcount);
    }

    /* Determine the scale factor */
    if (GETOBJ(int,3)==SESUT_ERMI_R_FSMTEST_SCALE_SPECIFIED) {
        sesut_ermi_r_fsmtest_current_scalefactor=GETOBJ(int,4);
        printf("\nScale factor is %u", sesut_ermi_r_fsmtest_current_scalefactor);
    } else {
        sesut_ermi_r_fsmtest_current_scalefactor=1;
        printf("\nScale factor is not specified. Assumed to be 1.");
    }

    /* Start GD,MIF and Cflow */
    if (GETOBJ(int,6)==SESUT_ERMI_R_FSMTEST_GD_SPECIFIED) {
        perform_gd=TRUE;
        sesut_gdmifcflow_result =
         sesut_execcommand(TRUE,"set memory debug incremental starting-time");
        if (!sesut_gdmifcflow_result) {
            printf("\nSESUT: set mem debug incremental starting-time "
                   "- not recognized");
            printf("\nSESUT: gd option ignored.");
            perform_gd=FALSE;
        }
    } else {
        perform_gd=FALSE;
    }
    if (GETOBJ(int,7)==SESUT_ERMI_R_FSMTEST_MIF_SPECIFIED) {
        perform_mif=TRUE;
        sesut_gdmifcflow_result = sesut_execcommand(TRUE,"mif on");
        if (!sesut_gdmifcflow_result) {
            printf("\nSESUT: mif on - not recognized");
            printf("\nSESUT: mif option ignored.");
            perform_mif=FALSE;
        }
    } else {
        perform_mif=FALSE;
    }
    if (GETOBJ(int,8)==SESUT_ERMI_R_FSMTEST_GCOV_SPECIFIED) {
        get_cflow=TRUE;
    } else {
        get_cflow=FALSE;
    }

    /* Print the values of parameters*/
    printf("\nValue(s) of parameter(s):");
    printf("\npeer_addr=%i",
      GETOBJ(paddr,1)->ip_addr);


    /* Let the output from the test begin on new line*/
    printf("\n");

    starttime=sesut_ermi_r_fsmtest_gettimestamp();
    start_freememory=sesut_ermi_r_fsmtest_getfreememory();

    /* This block will be used during the test to record count/time
     * for nodes/edges.
     */
    sesut_ermi_r_fsmtest_gettestinfoblock();
    if (sesut_ermi_r_fsmtest_current!=NULL) {
        sesut_ermi_r_fsmtest_current->testresult=SESUT_ERMI_R_FSMTEST_TEST_RESULT_UNKNOWN;
    }

    printf("Start Execution \n");
    if (sesut_global_log_startend) {
        buginf("\nSESUT Log: Test sesut_ermi_r_fsmtest started(CLI)");
    }
    sesut_global_current_testpass_fn=sesut_ermi_r_fsmtest_testpass;
    sesut_global_current_testfail_fn=sesut_ermi_r_fsmtest_testfail;

    
    
    /* Execute the test */
    for (sesut_ermi_r_fsmtest_current_repeatindex=0;
        sesut_ermi_r_fsmtest_current_repeatindex<sesut_ermi_r_fsmtest_current_repeatcount;
              sesut_ermi_r_fsmtest_current_repeatindex++) {
        if (sesut_ermi_r_fsmtest_dtd_notest==FALSE) {
            sesut_ermi_r_fsmtest(GETOBJ(paddr,1));
        }
        if (sesut_ermi_r_fsmtest_dtd_all||sesut_ermi_r_fsmtest_dtd_singlefn) {
            sesut_ermi_r_fsmtest_dtd_exec_tests();
        }
    }
    sesut_ermi_r_fsmtest_dtd_all=FALSE;
    sesut_ermi_r_fsmtest_dtd_singlefn=FALSE;
    sesut_ermi_r_fsmtest_dtd_notest=FALSE;
    sesut_global_current_testpass_fn=NULL;
    sesut_global_current_testfail_fn=NULL;
    
    
    sesut_current_executiontime=
                   sesut_ermi_r_fsmtest_getelapsedtime(starttime);
    sesut_current_memoryused=start_freememory-sesut_ermi_r_fsmtest_getfreememory();

    /* If we have a test information block, fill the block. */
    if (sesut_ermi_r_fsmtest_current!=NULL) {
        sesut_ermi_r_fsmtest_current->repeatcount=sesut_ermi_r_fsmtest_current_repeatcount;
        sesut_ermi_r_fsmtest_current->scalefactor=sesut_ermi_r_fsmtest_current_scalefactor;
        sesut_ermi_r_fsmtest_current->executiontime=sesut_current_executiontime;
        sesut_ermi_r_fsmtest_current->memoryused=sesut_current_memoryused;
        sesut_ermi_r_fsmtest_current->howinvoked=SESUT_ERMI_R_FSMTEST_CLI_IN_USE;
        
        /* Copy the string to testinfo block*/
        sesut_ermi_r_fsmtest_current->param1=malloc_named(sizeof(addrtype*),"sesut_ermi_r_fsmtest paddr 1");
        if (sesut_ermi_r_fsmtest_current->param1==NULL) {
            printf("\nCouldn't allocate memory to save unit test param string.\n");
        } else {
            *sesut_ermi_r_fsmtest_current->param1= *GETOBJ(paddr,1);
        }
	

        /* Save uint parameters */
        
    }
    sesut_ermi_r_fsmtest_times_cli_used++;

    if (perform_gd) {
        sesut_gdmifcflow_result=
          sesut_execcommand(TRUE,"show memory debug incremental leaks");
        if (!sesut_gdmifcflow_result) {
            printf("\nSESUT: show mem incremental leaks - not recognized");
        }
    }
    if (perform_mif) {
        sesut_gdmifcflow_result=sesut_execcommand(TRUE,"mif off");
        if (!sesut_gdmifcflow_result) {
            printf("\nSESUT: mif off - not recognized");
        }
    }
    if (get_cflow) {
        sesut_gdmifcflow_result=sesut_execcommand(TRUE,"cflow fastcopy");
        if (!sesut_gdmifcflow_result) {
            printf("\nSESUT: cflow fastcopy - not recognized");
        }
        sesut_gdmifcflow_result=sesut_execcommand(TRUE,"cflow listfiles 0");
        if (!sesut_gdmifcflow_result) {
            printf("\nSESUT: cflow listfiles 0 - not recognized");
        }
    }

    /* if the logger flush option is chosen, flush the log */
    if (sesutFlushLoggerAfterTest) {
	sesut_logger_flush();
    }

    switch (sesut_ermi_r_fsmtest_current->testresult) {
        case SESUT_ERMI_R_FSMTEST_TEST_PASSED:
            printf("\nUnit test %s passed (%d passes/%d failures)",
            "sesut_ermi_r_fsmtest",sesut_ermi_r_fsmtest_current->count_of_passes,
            sesut_ermi_r_fsmtest_current->count_of_failures);
            break;
        case SESUT_ERMI_R_FSMTEST_TEST_FAILED:
            printf("\nUnit test %s failed (%d passes/%d failures)",
            "sesut_ermi_r_fsmtest",sesut_ermi_r_fsmtest_current->count_of_passes,
            sesut_ermi_r_fsmtest_current->count_of_failures);
            break;
        case SESUT_ERMI_R_FSMTEST_TEST_RESULT_UNKNOWN:
            switch (sesut_ermi_r_fsmtest_default_result) {
            case SESUT_ERMI_R_FSMTEST_TEST_PASSED:
                sesut_ermi_r_fsmtest_current->testresult=SESUT_ERMI_R_FSMTEST_TEST_PASSED;
                printf("\nUnit test %s passed (default)","sesut_ermi_r_fsmtest");
                break;
            case SESUT_ERMI_R_FSMTEST_TEST_FAILED:
                sesut_ermi_r_fsmtest_current->testresult=SESUT_ERMI_R_FSMTEST_TEST_FAILED;
                printf("\nUnit test %s failed (default)","sesut_ermi_r_fsmtest");
                break;        
            default:
                printf("\nUnit test %s result is not known","sesut_ermi_r_fsmtest");
                break;
            }
            break;
        default:
            printf("\nInternal error - Unrecognized test result "
                   "for %s.","sesut_ermi_r_fsmtest");
    }
    printf("\nExecuted unit test %s","sesut_ermi_r_fsmtest");
    if (sesut_global_log_startend) {
        buginf("\nSESUT Log: Test sesut_ermi_r_fsmtest ended(CLI)");
    }
}

/*
 * This function drives the unit test.
 * Call this function to execute the test.
 * We need to create testinfo block and save information.
 */
void sesut_ermi_r_fsmtest_api (addrtype* peer_addr) {

    sesut_ermi_r_fsmtest_time starttime;
    ulong start_freememory;
    sesut_ermi_r_fsmtest_time sesut_current_executiontime;
    uint sesut_current_memoryused;

    sesut_ermi_r_fsmtest_current_repeatcount=sesut_ermi_r_fsmtest_default_repeatcount;
    sesut_ermi_r_fsmtest_current_scalefactor=1;
    starttime=sesut_ermi_r_fsmtest_gettimestamp();
    if (sesut_global_log_startend) {
        buginf("\nSESUT Log: Test sesut_ermi_r_fsmtest started(API)");
    }
    start_freememory=sesut_ermi_r_fsmtest_getfreememory();

    /* This block will be used during the test to record count/time
     * for nodes/edges.
     */
    sesut_ermi_r_fsmtest_gettestinfoblock();
    if (sesut_ermi_r_fsmtest_current!=NULL) {
        sesut_ermi_r_fsmtest_current->testresult=SESUT_ERMI_R_FSMTEST_TEST_RESULT_UNKNOWN;
    }
    sesut_global_current_testpass_fn=sesut_ermi_r_fsmtest_testpass;
    sesut_global_current_testfail_fn=sesut_ermi_r_fsmtest_testfail;

    
    
    /* Execute the test */
    for (sesut_ermi_r_fsmtest_current_repeatindex=0;
        sesut_ermi_r_fsmtest_current_repeatindex<sesut_ermi_r_fsmtest_current_repeatcount;
              sesut_ermi_r_fsmtest_current_repeatindex++) {
        sesut_ermi_r_fsmtest(peer_addr);
    }
    sesut_global_current_testpass_fn=NULL;
    sesut_global_current_testfail_fn=NULL;
    
    
    sesut_current_executiontime=
                   sesut_ermi_r_fsmtest_getelapsedtime(starttime);
    sesut_current_memoryused=start_freememory-sesut_ermi_r_fsmtest_getfreememory();

    /* If we have a test information block, fill the block. */
    if (sesut_ermi_r_fsmtest_current!=NULL) {
        sesut_ermi_r_fsmtest_current->repeatcount=sesut_ermi_r_fsmtest_current_repeatcount;
        sesut_ermi_r_fsmtest_current->scalefactor=sesut_ermi_r_fsmtest_current_scalefactor;
        sesut_ermi_r_fsmtest_current->executiontime=sesut_current_executiontime;
        sesut_ermi_r_fsmtest_current->memoryused=sesut_current_memoryused;
        sesut_ermi_r_fsmtest_current->howinvoked=SESUT_ERMI_R_FSMTEST_API_IN_USE;
        /* Save uint parameters */
        
        /* String parameters are not saved. We can't allocate memory
         * here because this function could be invoked in interrupt
         * context. We can't use the same locations used in parameters
         * because when we try to use the pointers(during status)
         * the memory may have been freed(and possibly reallocated).
         */
    }
    if (sesut_global_log_startend) {
        buginf("\nSESUT Log: Test sesut_ermi_r_fsmtest ended(API)");
    }
    sesut_ermi_r_fsmtest_times_api_used++;
    /* if the logger flush option is chosen, flush the log */
    if (sesutFlushLoggerAfterTest) {
	sesut_logger_flush();
    }
}

/*
 * This function executes the unit test using default values
 * for parameters.
 * We need to create testinfo block and save information.
 */
void sesut_ermi_r_fsmtest_api_defaultparams (sesut_repeat_scale_info 
                   *repeat_scale_data) {
    sesut_ermi_r_fsmtest_time starttime;
    ulong start_freememory;
    sesut_ermi_r_fsmtest_time sesut_current_executiontime;
    uint sesut_current_memoryused;

    if (repeat_scale_data->isScaleSpecified) {
        sesut_ermi_r_fsmtest_current_scalefactor=repeat_scale_data->scalefactor;
    } else {
        sesut_ermi_r_fsmtest_current_scalefactor=1;
    }
    if (sesut_global_log_startend) {
        buginf("\nSESUT Log: Test sesut_ermi_r_fsmtest started(API defaults)");
    }
    starttime=sesut_ermi_r_fsmtest_gettimestamp();
    start_freememory=sesut_ermi_r_fsmtest_getfreememory();
    /* This block will be used during the test to record count/time
     * for nodes/edges.
     */
    sesut_ermi_r_fsmtest_gettestinfoblock();
    if (sesut_ermi_r_fsmtest_current!=NULL) {
        sesut_ermi_r_fsmtest_current->testresult=SESUT_ERMI_R_FSMTEST_TEST_RESULT_UNKNOWN;
    }
    if (repeat_scale_data->isRepeatSpecified) {
        sesut_ermi_r_fsmtest_current_repeatcount=repeat_scale_data->repeatcount;
    } else {
        sesut_ermi_r_fsmtest_current_repeatcount=sesut_ermi_r_fsmtest_default_repeatcount;
    }
    sesut_global_current_testpass_fn=sesut_ermi_r_fsmtest_testpass;
    sesut_global_current_testfail_fn=sesut_ermi_r_fsmtest_testfail;

    
    
    /* Execute the test */
    for (sesut_ermi_r_fsmtest_current_repeatindex=0;
         sesut_ermi_r_fsmtest_current_repeatindex<sesut_ermi_r_fsmtest_current_repeatcount;
              sesut_ermi_r_fsmtest_current_repeatindex++) {
        sesut_ermi_r_fsmtest(NULL);
    }
    sesut_global_current_testpass_fn=NULL;
    sesut_global_current_testfail_fn=NULL;
    
    
    sesut_current_executiontime=
                   sesut_ermi_r_fsmtest_getelapsedtime(starttime);
    sesut_current_memoryused=start_freememory-sesut_ermi_r_fsmtest_getfreememory();

    /* If we have a test information block, fill the block. */
    if (sesut_ermi_r_fsmtest_current!=NULL) {
        sesut_ermi_r_fsmtest_current->repeatcount=sesut_ermi_r_fsmtest_current_repeatcount;
        sesut_ermi_r_fsmtest_current->scalefactor=sesut_ermi_r_fsmtest_current_scalefactor;
        sesut_ermi_r_fsmtest_current->executiontime=sesut_current_executiontime;
        sesut_ermi_r_fsmtest_current->memoryused=sesut_current_memoryused;
        sesut_ermi_r_fsmtest_current->howinvoked=SESUT_ERMI_R_FSMTEST_DEFAPI_IN_USE;
        /* Save uint parameters */
        
        /* String parameters are not saved. We can't allocate memory
         * here because this function could be invoked in interrupt
         * context. We can't use the same locations used in parameters
         * because when we try to use the pointers(during status)
         * the memory may have been freed(and possibly reallocated).
         */
    }
    if (sesut_global_log_startend) {
        buginf("\nSESUT Log: Test sesut_ermi_r_fsmtest ended(API defaults)");
    }
    sesut_ermi_r_fsmtest_times_defaultapi_used++;

    /* if the logger flush option is chosen, flush the log */
    if (sesutFlushLoggerAfterTest) {
	sesut_logger_flush();
    }
}


/*
 * If trace is on print the node/edge just entered. 
 * If not the first node increment the time for the last
 * node/edge.
 */
void sesut_ermi_r_fsmtest_graph_entry_action (uint index) {
    if (sesut_ermi_r_fsmtest_trace_status==SESUT_ERMI_R_FSMTEST_TRACE_ON) {
        buginf("\nSESUT: sesut_ermi_r_fsmtest - Entering %s",
                     sesut_ermi_r_fsmtest_graphLabels[index]);
    }
    if (sesut_ermi_r_fsmtest_current!=NULL) {
        sesut_ermi_r_fsmtest_current->nodes_and_edges[index].count++;
    }
    if (sesut_ermi_r_fsmtest_start_test==SESUT_ERMI_R_FSMTEST_THISIS_FIRSTNODE) {
        sesut_ermi_r_fsmtest_start_test=SESUT_ERMI_R_FSMTEST_THISISNOT_FIRSTNODE;
    } else {
        if (sesut_ermi_r_fsmtest_current!=NULL) {
            sesut_ermi_r_fsmtest_current->
                nodes_and_edges[sesut_ermi_r_fsmtest_last_index].time+=
                sesut_ermi_r_fsmtest_getelapsedtime(sesut_ermi_r_fsmtest_last_timestamp);
        }
    }
    sesut_ermi_r_fsmtest_last_index=index;
    sesut_ermi_r_fsmtest_last_timestamp=sesut_ermi_r_fsmtest_gettimestamp();
}

/* DTD - Execute tests for all functions or a single function.
 * Write a message to the log before execution of the tests.
 */
void sesut_ermi_r_fsmtest_dtd_exec_tests() {
    char timestamp[CURRENT_TIME_STRING_MINBUF];
    char *dtd_all_message=" DTD(all) started
";
    char *dtd_single_message=" DTD(fn) started
";
    

    if (sesut_ermi_r_fsmtest_dtd_availability==FALSE) {
        printf("\nSESUT: Error - DTD is not used in sesut_ermi_r_fsmtest");
    }
    printf("\nSESUT(DTD) StartId - %lld, NextId - %lld and EndId - %lld",
            sesut_ermi_r_fsmtest_dtd_start,sesut_ermi_r_fsmtest_dtd_next,
            sesut_ermi_r_fsmtest_dtd_end);
    current_time_string(timestamp);
    sesut_dtdtestlog_write(timestamp,strlen(timestamp));
    if (sesut_ermi_r_fsmtest_dtd_all) {
        printf("\nSESUT(DTD all) Inter-test delay is %d seconds",
                     sesut_ermi_r_fsmtest_dtd_all_delay);
        sesut_dtdtestlog_write(dtd_all_message,strlen(dtd_all_message));
        
    } else {
        sesut_dtdtestlog_write(dtd_single_message,strlen(dtd_single_message));
        switch (sesut_ermi_r_fsmtest_dtd_fnid) {
            
            default: printf("\nSESUT - sesut_ermi_r_fsmtest Internal error - "
                       "Unrecognized DTD function code %d.",
                       sesut_ermi_r_fsmtest_dtd_fnid);
        }
    }
}

